#!run
import * as path from "node:path";
import * as fs from "node:fs";

export async function main() {
  const cwd = this.getcwd() + "";

  // read package.json in cwd
  const pkgPath = path.join(cwd, "package.json");
  const pkg = JSON.parse(fs.readFileSync(pkgPath, "utf-8"));

  // read workspaces field
  const workspaces = pkg.workspaces ?? [];

  console.log(workspaces)
  const nodeModules = path.join(cwd, "node_modules");

  for (const pattern of workspaces) {
    // resolve glob-less workspace paths (e.g. "packages/foo" or "packages/*")
    const entries = pattern.includes("*")
      ? [...this.glob(pattern)].map(e=>path.join(cwd,e))
      : [path.join(cwd, pattern)];
    console.log(entries)
    for (const pkgDir of entries) {
      if (!fs.existsSync(pkgDir)) continue;

      const subPkgPath = path.join(pkgDir, "package.json");
      if (!fs.existsSync(subPkgPath)) continue;

      const subPkg = JSON.parse(fs.readFileSync(subPkgPath, "utf-8"));
      const pkgName = subPkg.name;
      if (!pkgName) continue;

      const linkPath = path.join(nodeModules, pkgName);

      // if there is non-link folder, console.warn
      if (fs.existsSync(linkPath)) {
        const stat = fs.lstatSync(linkPath);
        if (!stat.isSymbolicLink()) {
          console.warn(
            `[warn] "${linkPath}" exists but is not a symlink — skipping.`
          );
          continue;
        }
        fs.unlinkSync(linkPath);
      }

      // symlink them from node_modules
      const nameDir = path.dirname(path.join(nodeModules, pkgName));
      fs.mkdirSync(nameDir, { recursive: true });
      fs.symlinkSync(pkgDir, linkPath, "junction");
    }
  }
}